  /**
   * Process multiple emails sequentially with shared session context
   *
   * @param emails - Array of email messages to classify
   * @returns Array of classification results or error results
   */
  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
    const results: Array<ClassificationResult | ClassificationErrorResult> = [];

    // Create batch session
    const session = createClassificationSession(this.config.processingConfig, 'sequential', emails.length);

    for (let i = 0; i < emails.length; i++) {
      const email = emails[i];
      const startTime = Date.now();
      try {
        // Create result for this email
        const result = createClassificationResult(email.id, session.id, i);

        // Execute pipeline stages sequentially
        executeHardAssertions(email, session, result, this.getHardAssertionConfig());
        executeStrongIndicators(email, session, result, this.getStrongIndicatorConfig());
        executeRuleScoring(email, session, result, this.getRuleScoringConfig());
        executeAttributeDetection(email, session, result, this.getAttributeDetectionConfig());
        executeAttributeInfluence(email, session, result, this.config);
        executeDisambiguation(email, session, result, this.config);
        executeMultiLabelSelection(email, session, result, this.getMultiLabelConfig(), this.getConfidenceThresholds());

        // Update processing time and mark successful
        result.processingDurationMs = Date.now() - startTime;
        result.processedAt = new Date();
        incrementSessionSuccess(session);

        results.push(result);
      } catch (error) {
        // Continue processing batch on individual email error
        incrementSessionError(session, email.id, 'pipeline', error instanceof Error ? error.message : String(error));
        results.push({
          error: error instanceof Error ? error : new Error(String(error)),
          emailId: email.id,
          processingDurationMs: Date.now() - startTime,
        });
      }
    }

    // Finalize session after all emails processed
    finalizeClassificationSession(session);

    return results;
  }
}

