  session.completedAt = new Date();

  // Calculate final performance metrics
  const totalDurationMs = session.completedAt.getTime() - session.startedAt.getTime();
  session.performanceMetrics.totalDurationMs = totalDurationMs;

  if (session.successCount > 0) {
    session.performanceMetrics.avgEmailDurationMs = totalDurationMs / session.successCount;
  }
}

